'use strict';

const PresentationSubstrate = (() => {

    const PHI = 1.618033988749895;
    function zxy(x, y) { return x * y; }





    let _renderer = null, _scene = null, _camera = null, _controls = null;
    let _animLoop = null;

    function initRender(canvas, opts = {}) {
        if (typeof THREE === 'undefined') throw new Error('[Presentation L6] THREE.js not loaded');

        _renderer = new THREE.WebGLRenderer({
            canvas, antialias: opts.antialias !== false, alpha: opts.alpha || false
        });
        _renderer.setSize(window.innerWidth, window.innerHeight);
        _renderer.setPixelRatio(Math.min(window.devicePixelRatio, 2));
        if (opts.shadows) { _renderer.shadowMap.enabled = true; _renderer.shadowMap.type = THREE.PCFSoftShadowMap; }

        _scene = new THREE.Scene();
        _scene.background = new THREE.Color(opts.background || 0x000000);

        const aspect = window.innerWidth / window.innerHeight;
        _camera = new THREE.PerspectiveCamera(opts.fov || 60, aspect, opts.near || 0.1, opts.far || 1000);
        _camera.position.set(0, opts.cameraHeight || 25, opts.cameraDistance || 25);
        _camera.lookAt(0, 0, 0);

        if (typeof THREE.OrbitControls !== 'undefined') {
            _controls = new THREE.OrbitControls(_camera, _renderer.domElement);
            _controls.enableDamping = true;
            _controls.dampingFactor = 0.08;
        }

        window.addEventListener('resize', _onResize);
        return { renderer: _renderer, scene: _scene, camera: _camera, controls: _controls };
    }

    function _onResize() {
        if (!_camera || !_renderer) return;
        _camera.aspect = window.innerWidth / window.innerHeight;
        _camera.updateProjectionMatrix();
        _renderer.setSize(window.innerWidth, window.innerHeight);
    }

    function startRenderLoop(onFrame) {
        if (_animLoop) return;
        const loop = (t) => {
            _animLoop = requestAnimationFrame(loop);



            if (typeof Wave !== 'undefined') Wave.tick(t / 1000);
            if (_controls) _controls.update();
            if (onFrame) onFrame(t, _scene, _camera);
            _renderer.render(_scene, _camera);
        };
        _animLoop = requestAnimationFrame(loop);
    }

    function stopRenderLoop() { if (_animLoop) { cancelAnimationFrame(_animLoop); _animLoop = null; } }

    function addToScene(obj)      { if (_scene) _scene.add(obj); }
    function removeFromScene(obj) { if (_scene) _scene.remove(obj); }





    let _audioCtx = null, _masterGain = null, _musicGain = null, _sfxGain = null;
    const _buffers = new Map();

    function initAudio() {
        if (_audioCtx) return _audioCtx;
        _audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        _masterGain = _audioCtx.createGain();
        _musicGain  = _audioCtx.createGain();
        _sfxGain    = _audioCtx.createGain();
        _musicGain.connect(_masterGain);
        _sfxGain.connect(_masterGain);
        _masterGain.connect(_audioCtx.destination);
        return _audioCtx;
    }

    function setVolume(channel, val) {
        const gain = channel === 'music' ? _musicGain : channel === 'sfx' ? _sfxGain : _masterGain;
        if (gain) gain.gain.setTargetAtTime(val, _audioCtx.currentTime, 0.05);
    }

    function playSFX(buffer, opts = {}) {
        if (!_audioCtx || !buffer) return;
        const src = _audioCtx.createBufferSource();
        src.buffer = buffer;
        src.connect(_sfxGain);
        if (opts.rate) src.playbackRate.value = opts.rate;
        src.start(0);
        return src;
    }

    async function loadAudioBuffer(url) {
        if (_buffers.has(url)) return _buffers.get(url);
        if (!_audioCtx) initAudio();
        const resp = await fetch(url);
        const buf = await _audioCtx.decodeAudioData(await resp.arrayBuffer());
        _buffers.set(url, buf);
        return buf;
    }





    function setCameraPosition(x, y, z) { if (_camera) _camera.position.set(x, y, z); }
    function setCameraTarget(x, y, z)   { if (_controls) _controls.target.set(x, y, z); else if (_camera) _camera.lookAt(x, y, z); }

    function animateCamera(pos, target, duration = 1000) {
        if (!_camera) return;
        const start = { px: _camera.position.x, py: _camera.position.y, pz: _camera.position.z };
        const t0 = performance.now();
        const step = () => {
            const p = Math.min(1, (performance.now() - t0) / duration);
            const ease = p < 0.5 ? 2 * p * p : 1 - Math.pow(-2 * p + 2, 2) / 2;
            _camera.position.set(
                start.px + (pos.x - start.px) * ease,
                start.py + (pos.y - start.py) * ease,
                start.pz + (pos.z - start.pz) * ease
            );
            if (target && _controls) _controls.target.set(target.x, target.y, target.z);
            if (p < 1) requestAnimationFrame(step);
        };
        requestAnimationFrame(step);
    }





    let _musicPlaying = false, _currentTrack = null;

    function playNote(freq, duration = 0.15, type = 'square', gain = 0.12) {
        if (!_audioCtx) initAudio();
        const osc = _audioCtx.createOscillator();
        const g   = _audioCtx.createGain();
        osc.type = type;
        osc.frequency.value = freq;
        g.gain.setValueAtTime(gain, _audioCtx.currentTime);
        g.gain.exponentialRampToValueAtTime(0.001, _audioCtx.currentTime + duration);
        osc.connect(g); g.connect(_musicGain);
        osc.start(); osc.stop(_audioCtx.currentTime + duration);
        return osc;
    }

    function playMelody(notes, bpm = 140, loop = false) {
        stopMusic();
        _musicPlaying = true;
        const beatLen = 60 / bpm;
        let idx = 0;
        const step = () => {
            if (!_musicPlaying) return;
            const n = notes[idx % notes.length];
            if (n && n.freq) playNote(n.freq, (n.dur || 1) * beatLen * 0.9, n.type || 'square', n.vol || 0.12);
            idx++;
            if (idx >= notes.length && !loop) { _musicPlaying = false; return; }
            _currentTrack = setTimeout(step, beatLen * (n?.dur || 1) * 1000);
        };
        step();
    }

    function stopMusic() {
        _musicPlaying = false;
        if (_currentTrack) { clearTimeout(_currentTrack); _currentTrack = null; }
    }





    const _themes = new Map();
    let _activeTheme = null;

    function registerTheme(name, config) { _themes.set(name, config); }

    function setTheme(name) {
        const t = _themes.get(name);
        if (!t) return false;
        _activeTheme = t;
        if (t.background && _scene) _scene.background = new THREE.Color(t.background);
        if (t.cssVars) Object.entries(t.cssVars).forEach(([k, v]) => document.documentElement.style.setProperty(k, v));
        return true;
    }

    function getTheme()      { return _activeTheme; }
    function getThemeValue(k) { return _activeTheme ? _activeTheme[k] : undefined; }





    function createParticleBurst(pos, count = 20, color = 0xffaa00) {
        if (!_scene || typeof THREE === 'undefined') return;
        const geo = new THREE.BufferGeometry();
        const verts = new Float32Array(count * 3);
        for (let i = 0; i < count * 3; i++) verts[i] = 0;
        geo.setAttribute('position', new THREE.BufferAttribute(verts, 3));
        const mat = new THREE.PointsMaterial({ color, size: 0.15, transparent: true });
        const pts = new THREE.Points(geo, mat);
        pts.position.copy(pos);
        _scene.add(pts);

        const velocities = Array.from({ length: count }, () => ({
            x: (Math.random() - 0.5) * 0.3,
            y: Math.random() * 0.2 + 0.1,
            z: (Math.random() - 0.5) * 0.3
        }));
        let frame = 0;
        const anim = () => {
            frame++;
            const arr = geo.attributes.position.array;
            for (let i = 0; i < count; i++) {
                arr[i * 3]     += velocities[i].x;
                arr[i * 3 + 1] += velocities[i].y;
                arr[i * 3 + 2] += velocities[i].z;
                velocities[i].y -= 0.008;
            }
            geo.attributes.position.needsUpdate = true;
            mat.opacity = 1 - frame / 60;
            if (frame < 60) requestAnimationFrame(anim);
            else _scene.remove(pts);
        };
        requestAnimationFrame(anim);
    }


    return Object.freeze({
        name:    'Presentation Substrate',
        layer:   6,
        genesis: 'Mind',
        surface: 'z=xy',
        PHI, zxy,

        initRender, startRenderLoop, stopRenderLoop,
        addToScene, removeFromScene,
        getScene: () => _scene, getCamera: () => _camera,
        getRenderer: () => _renderer, getControls: () => _controls,

        initAudio, setVolume, playSFX, loadAudioBuffer,
        getAudioContext: () => _audioCtx,

        setCameraPosition, setCameraTarget, animateCamera,

        playNote, playMelody, stopMusic,
        isMusicPlaying: () => _musicPlaying,

        registerTheme, setTheme, getTheme, getThemeValue,

        createParticleBurst,

        stats: () => ({ buffers: _buffers.size, themes: _themes.size, rendering: !!_animLoop }),


        below: () => typeof SessionSubstrate !== 'undefined' ? SessionSubstrate : null
    });
})();

if (typeof window !== 'undefined') window.PresentationSubstrate = PresentationSubstrate;
if (typeof module !== 'undefined') module.exports = PresentationSubstrate;
